import logging
import logging.handlers
import os

# Set the log storage location
LOG_DIR = 'logs'

# Create the log directory if it doesn't exist
os.makedirs(LOG_DIR, exist_ok=True)

# Configure the logger
logger = logging.getLogger(__name__)
logger.setLevel(logging.INFO)

# Create a rotating file handler
handler = logging.handlers.RotatingFileHandler(
    os.path.join(LOG_DIR, 'app.log'),
    maxBytes=1024 * 1024,  # Maximum size of a log file in bytes
    backupCount=5  # Number of old log files to keep
)

# Set the file permissions for the log file
os.chmod(os.path.join(LOG_DIR, 'app.log'), 0o644)

# Add the handler to the logger
logger.addHandler(handler)

# Example usage
logger.info('Application started')
logger.error('An error occurred')